var documenterSearchIndex = {"docs":
[{"location":"era5/#ERA5-Reanalysis","page":"ERA5","title":"ERA5 Reanalysis","text":"","category":"section"},{"location":"era5/#Overview","page":"ERA5","title":"Overview","text":"ERA5 is the fifth generation ECMWF atmospheric reanalysis of the global climate, covering 1940 to the present with hourly temporal resolution and 0.25° x 0.25° spatial resolution on 37 pressure levels.\n\nThis data loader provides access to ERA5 pressure-level data via the Copernicus Climate Data Store (CDS) API or from pre-downloaded local NetCDF files.\n\nReference: Hersbach, H., et al. (2020). The ERA5 global reanalysis. Quarterly Journal of the Royal Meteorological Society, 146(730), 1999-2049. doi:10.1002/qj.3803","category":"section"},{"location":"era5/#Setup","page":"ERA5","title":"Setup","text":"","category":"section"},{"location":"era5/#CDS-API-Key","page":"ERA5","title":"CDS API Key","text":"To download ERA5 data automatically, you need a free CDS account:\n\nRegister at https://cds.climate.copernicus.eu/\nAccept the ERA5 data licence\nCreate ~/.cdsapirc with:\n\nurl: https://cds.climate.copernicus.eu/api\nkey: <your-api-key>\n\nAlternatively, set the CDSAPI_KEY environment variable.","category":"section"},{"location":"era5/#Pre-downloaded-Data","page":"ERA5","title":"Pre-downloaded Data","text":"If you already have ERA5 data as NetCDF files, use mirror=\"file:///path/to/data\". Files should be named era5_pl_YYYY_MM.nc (one file per month, containing all variables).","category":"section"},{"location":"era5/#Implementation","page":"ERA5","title":"Implementation","text":"To use ERA5 data in production, you will need a CDS API key (see Setup above). The example below uses a small synthetic dataset to demonstrate the API.\n\nusing EarthSciData, EarthSciMLBase # hide\nusing ModelingToolkit, DataFrames # hide\nusing ModelingToolkit: t # hide\nusing Dates # hide\nusing DynamicQuantities # hide\nusing DynamicQuantities: dimension # hide\nusing NCDatasets # hide\n# hide\n# Generate a small synthetic ERA5 NetCDF file for this example. # hide\nera5_dir = mktempdir() # hide\nlon_vals = Float64.(-130.0:5.0:-60.0) # hide\nlat_vals = Float64.(20.0:5.0:50.0) # hide\nplev_vals = Float64.([1000, 975, 950, 925]) # hide\ntime_vals = [DateTime(2022, 1, d, h) for d in 1:31 for h in 0:6:18] # hide\nera5_vars = Dict( # hide\n    \"t\" => (\"K\", \"Temperature\", 260.0, 300.0), # hide\n    \"u\" => (\"m s**-1\", \"U component of wind\", -15.0, 15.0), # hide\n    \"v\" => (\"m s**-1\", \"V component of wind\", -15.0, 15.0), # hide\n    \"w\" => (\"Pa s**-1\", \"Vertical velocity\", -1.0, 1.0), # hide\n    \"q\" => (\"kg kg**-1\", \"Specific humidity\", 0.0, 0.02), # hide\n    \"r\" => (\"%\", \"Relative humidity\", 0.0, 100.0), # hide\n    \"z\" => (\"m**2 s**-2\", \"Geopotential\", 0.0, 1e5), # hide\n    \"d\" => (\"s**-1\", \"Divergence\", -1e-5, 1e-5), # hide\n    \"vo\" => (\"s**-1\", \"Vorticity (relative)\", -1e-5, 1e-5), # hide\n    \"o3\" => (\"kg kg**-1\", \"Ozone mass mixing ratio\", 0.0, 1e-5), # hide\n    \"cc\" => (\"(0 - 1)\", \"Fraction of cloud cover\", 0.0, 1.0), # hide\n    \"ciwc\" => (\"kg kg**-1\", \"Specific cloud ice water content\", 0.0, 1e-5), # hide\n    \"clwc\" => (\"kg kg**-1\", \"Specific cloud liquid water content\", 0.0, 1e-5), # hide\n    \"crwc\" => (\"kg kg**-1\", \"Specific rain water content\", 0.0, 1e-5), # hide\n    \"cswc\" => (\"kg kg**-1\", \"Specific snow water content\", 0.0, 1e-5), # hide\n    \"pv\" => (\"K m**2 kg**-1 s**-1\", \"Potential vorticity\", -1e-5, 1e-5), # hide\n) # hide\nNCDataset(joinpath(era5_dir, \"era5_pl_2022_01.nc\"), \"c\") do ds # hide\n    nlon, nlat, nplev, ntime = length(lon_vals), length(lat_vals), length(plev_vals), length(time_vals) # hide\n    defDim(ds, \"longitude\", nlon) # hide\n    defDim(ds, \"latitude\", nlat) # hide\n    defDim(ds, \"pressure_level\", nplev) # hide\n    defDim(ds, \"valid_time\", ntime) # hide\n    defVar(ds, \"longitude\", Float64, (\"longitude\",))[:] = lon_vals # hide\n    defVar(ds, \"latitude\", Float64, (\"latitude\",))[:] = lat_vals # hide\n    defVar(ds, \"pressure_level\", Float64, (\"pressure_level\",))[:] = plev_vals # hide\n    nctime = defVar(ds, \"valid_time\", Float64, (\"valid_time\",), # hide\n        attrib = Dict(\"units\" => \"hours since 1900-01-01 00:00:00\", # hide\n                      \"calendar\" => \"proleptic_gregorian\")) # hide\n    nctime[:] = time_vals # hide\n    for (vname, (units, long_name, vmin, vmax)) in era5_vars # hide\n        ncvar = defVar(ds, vname, Float32, # hide\n            (\"longitude\", \"latitude\", \"pressure_level\", \"valid_time\"), # hide\n            attrib = Dict(\"units\" => units, \"long_name\" => long_name)) # hide\n        data = [Float32(vmin + (vmax - vmin) * (i + j + k + ti) / (nlon + nlat + nplev + ntime)) # hide\n                for i in 1:nlon, j in 1:nlat, k in 1:nplev, ti in 1:ntime] # hide\n        ncvar[:, :, :, :] = data # hide\n    end # hide\nend # hide\nnothing # hide\n\nusing EarthSciData, EarthSciMLBase\nusing ModelingToolkit, DataFrames\nusing ModelingToolkit: t\nusing Dates\nusing DynamicQuantities\nusing DynamicQuantities: dimension\n\ndomain = DomainInfo(DateTime(2022, 1, 1), DateTime(2022, 1, 3);\n    latrange = deg2rad(20.0f0):deg2rad(5.0):deg2rad(50.0f0),\n    lonrange = deg2rad(-130.0f0):deg2rad(5.0):deg2rad(-60.0f0),\n    levrange = 1:4,\n)\n\nera5 = ERA5(domain; mirror=\"file://$(era5_dir)\")","category":"section"},{"location":"era5/#State-Variables","page":"ERA5","title":"State Variables","text":"vars = unknowns(era5)\nDataFrame(\n    :Name => [string(Symbolics.tosymbol(v, escape = false)) for v in vars],\n    :Units => [dimension(ModelingToolkit.get_unit(v)) for v in vars],\n    :Description => [ModelingToolkit.getdescription(v) for v in vars]\n)","category":"section"},{"location":"era5/#Equations","page":"ERA5","title":"Equations","text":"eqs = equations(era5)","category":"section"},{"location":"era5/#Available-Variables","page":"ERA5","title":"Available Variables","text":"ERA5 pressure-level variables include:\n\nShort Name Long Name Units\nt Temperature K\nu U component of wind m s⁻¹\nv V component of wind m s⁻¹\nw Vertical velocity Pa s⁻¹\nq Specific humidity kg kg⁻¹\nr Relative humidity %\nz Geopotential m² s⁻²\nd Divergence s⁻¹\nvo Vorticity s⁻¹\no3 Ozone mass mixing ratio kg kg⁻¹\ncc Fraction of cloud cover (0-1)\nciwc Specific cloud ice water content kg kg⁻¹\nclwc Specific cloud liquid water content kg kg⁻¹\ncrwc Specific rain water content kg kg⁻¹\ncswc Specific snow water content kg kg⁻¹\npv Potential vorticity K m² kg⁻¹ s⁻¹","category":"section"},{"location":"era5/#Pressure-Levels","page":"ERA5","title":"Pressure Levels","text":"ERA5 provides data on 37 pressure levels from 1000 hPa (surface) to 1 hPa (stratosphere). The level index maps to pressure as follows:\n\nIndex Pressure (hPa) Index Pressure (hPa)\n1 1000 20 300\n2 975 21 250\n3 950 22 225\n4 925 23 200\n5 900 24 175\n6 875 25 150\n7 850 26 125\n8 825 27 100\n9 800 28 70\n10 775 29 50\n11 750 30 30\n12 700 31 20\n13 650 32 10\n14 600 33 7\n15 550 34 5\n16 500 35 3\n17 450 36 2\n18 400 37 1\n19 350  ","category":"section"},{"location":"era5/#EarthSciData.ERA5","page":"ERA5","title":"EarthSciData.ERA5","text":"ERA5(domaininfo; name, mirror, variables, stream)\n\n\nA data loader for ERA5 reanalysis data on pressure levels from the Copernicus Climate Data Store (CDS).\n\nERA5 is the fifth generation ECMWF atmospheric reanalysis of the global climate, covering 1940 to present with hourly temporal resolution and 0.25deg x 0.25deg spatial resolution on 37 pressure levels.\n\nAuthentication: Requires a CDS API key. Either:\n\nSet ENV[\"CDSAPI_KEY\"]\nCreate ~/.cdsapirc with url: https://cds.climate.copernicus.eu/api and key: <your-key>\n\nPre-downloaded data: Pass mirror=\"file:///path/to/data\" to use local NetCDF files. Expected filenames: era5_pl_YYYY_MM.nc containing all variables for that month.\n\nAvailable variables (all on pressure levels): temperature, u/v wind, vertical velocity, specific/relative humidity, geopotential, divergence, vorticity, ozone, cloud fractions, potential vorticity.\n\nThe native data type for this dataset is Float32.\n\nstream specifies whether the data should be streamed in as needed or loaded all at once.\n\n\n\n\n\n","category":"function"},{"location":"landfire/#LANDFIRE-Fuel-Models","page":"LANDFIRE","title":"LANDFIRE Fuel Models","text":"","category":"section"},{"location":"landfire/#Overview","page":"LANDFIRE","title":"Overview","text":"LANDFIRE (Landscape Fire and Resource Management Planning Tools) provides geospatial data for wildland fire management across the United States. This data loader provides fire behavior fuel model (FBFM) classifications at 30m resolution over the contiguous United States (CONUS).\n\nTwo fuel model products are available:\n\nFBFM13: Anderson 13 fire behavior fuel models (codes 1–13), the classic fuel classification system.\nFBFM40: Scott & Burgan 40 fuel models (codes 101–204), a more detailed classification.\n\nBoth products include non-burnable codes: 91 (urban/developed), 92 (snow/ice), 93 (agriculture), 98 (water), and 99 (barren). Code 0 indicates no fuel data.\n\nThe fuel model codes from LANDFIRE map directly to fuel property dictionaries (e.g., fuel bed depth, moisture of extinction, surface-area-to-volume ratios) used in fire spread models such as the Rothermel model.\n\nReference: LANDFIRE: Landscape Fire and Resource Management Planning Tools. U.S. Department of the Interior, Geological Survey. https://landfire.gov/","category":"section"},{"location":"landfire/#Implementation","page":"LANDFIRE","title":"Implementation","text":"Data is downloaded from the LANDFIRE ImageServer REST API as GeoTIFF files. Because this is categorical (integer-valued) data, nearest-neighbour interpolation (BSpline(Constant())) is used for regridding instead of the bilinear interpolation used by other data sources. This preserves the integer fuel model codes.","category":"section"},{"location":"landfire/#Variables","page":"LANDFIRE","title":"Variables","text":"using EarthSciData, EarthSciMLBase\nusing ModelingToolkit, DynamicQuantities, DataFrames\nusing ModelingToolkit: t\nusing DynamicQuantities: dimension\nusing Dates\n\ndomain = DomainInfo(\n    DateTime(2018, 11, 8), DateTime(2018, 11, 9);\n    lonrange = deg2rad(-121.7):deg2rad(0.01):deg2rad(-121.5),\n    latrange = deg2rad(39.7):deg2rad(0.01):deg2rad(39.8),\n    levrange = 1:1\n)\n\nlandfire = LANDFIRE(domain; resolution = 10.0)\n\nfunction table(vars)\n    DataFrame(\n        :Name => [string(Symbolics.tosymbol(v, escape = false)) for v in vars],\n        :Units => [dimension(ModelingToolkit.get_unit(v)) for v in vars],\n        :Description => [ModelingToolkit.getdescription(v) for v in vars]\n    )\nend\ntable(unknowns(landfire))","category":"section"},{"location":"landfire/#Parameters","page":"LANDFIRE","title":"Parameters","text":"table(parameters(landfire))","category":"section"},{"location":"landfire/#Equations","page":"LANDFIRE","title":"Equations","text":"equations(landfire)","category":"section"},{"location":"landfire/#EarthSciData.LANDFIRE","page":"LANDFIRE","title":"EarthSciData.LANDFIRE","text":"LANDFIRE(\n    domaininfo;\n    name,\n    product,\n    version,\n    resolution,\n    stream\n)\n\n\nCreate a ModelingToolkit System that provides fuel model data from LANDFIRE.\n\nThe system exposes a single variable fuel_model (dimensionless) interpolated to the simulation coordinates using nearest-neighbour interpolation (appropriate for categorical data).\n\nArguments\n\ndomaininfo: A DomainInfo specifying the spatial and temporal domain.\nname: System name (default :LANDFIRE).\nproduct: LANDFIRE product (default \"FBFM13\" for Anderson 13 fuel models).\nversion: LANDFIRE version (default \"LF2022\").\nresolution: Target resolution in arc-seconds (default 1.0 ≈ 30m).\nstream: Whether to stream data lazily (default true).\n\nExample\n\nusing EarthSciData, EarthSciMLBase, ModelingToolkit, Dates\ndomain = DomainInfo(\n    DateTime(2018, 11, 8), DateTime(2018, 11, 9);\n    lonrange = deg2rad(-121.7):deg2rad(0.01):deg2rad(-121.5),\n    latrange = deg2rad(39.7):deg2rad(0.01):deg2rad(39.8),\n    levrange = 1:1\n)\nfuel = LANDFIRE(domain)\n\n\n\n\n\n","category":"function"},{"location":"benchmarks/#Redirecting...","page":"🔗 Benchmarks","title":"Redirecting...","text":"<html>\n<head>\n    <meta http-equiv=\"refresh\" content=\"0; url=https://data.earthsci.dev/benchmarks/\" />\n</head>\n<body>\n    <p>If you are not redirected automatically, follow this <a href=\"https://data.earthsci.dev/benchmarks/\">link</a>.</p>\n</body>\n</html>","category":"section"},{"location":"ceds/#CEDS-Global-Emissions","page":"CEDS","title":"CEDS Global Emissions","text":"We have a data loader for CEDS (Community Emissions Data System) global gridded anthropogenic emissions, CEDS.\n\nCEDS provides monthly global anthropogenic emissions at 0.5° × 0.5° resolution from 1750 to 2023 in units of kg m⁻² s⁻¹, with 8 anthropogenic sectors.\n\nReference: Hoesly, R. M., et al. (2018). Historical (1750–2014) anthropogenic emissions of reactive gases and aerosols from the Community Emissions Data System (CEDS). Geoscientific Model Development, 11, 369–408. https://doi.org/10.5194/gmd-11-369-2018","category":"section"},{"location":"ceds/#Equations","page":"CEDS","title":"Equations","text":"This is what its equation system looks like:\n\nusing EarthSciData, EarthSciMLBase\nusing ModelingToolkit, DynamicQuantities, DataFrames\nusing ModelingToolkit: t\nusing DynamicQuantities: dimension\nusing Dates\n\ndomain = DomainInfo(\n    DateTime(2016, 5, 1), DateTime(2016, 5, 2);\n    lonrange = deg2rad(-180):deg2rad(2.5):deg2rad(175),\n    latrange = deg2rad(-85):deg2rad(2):deg2rad(85),\n    levrange = 1:10,\n    u_proto = zeros(Float32, 1, 1, 1, 1)\n)\n\nemis = CEDS(domain; species = [\"SO2\", \"NOx\", \"CO\"])","category":"section"},{"location":"ceds/#Variables","page":"CEDS","title":"Variables","text":"Here are the variables in tabular format:\n\nfunction table(vars)\n    DataFrame(\n        :Name => [string(Symbolics.tosymbol(v, escape = false)) for v in vars],\n        :Units => [dimension(ModelingToolkit.get_unit(v)) for v in vars],\n        :Description => [ModelingToolkit.getdescription(v) for v in vars]\n    )\nend\ntable(unknowns(emis))","category":"section"},{"location":"ceds/#Parameters","page":"CEDS","title":"Parameters","text":"Finally, here are the parameters in tabular format:\n\ntable(parameters(emis))","category":"section"},{"location":"edgar_v81/#EDGAR-v8.1-Global-Air-Pollutant-Emissions","page":"EDGAR v8.1","title":"EDGAR v8.1 Global Air Pollutant Emissions","text":"","category":"section"},{"location":"edgar_v81/#Overview","page":"EDGAR v8.1","title":"Overview","text":"We have a data loader for EDGAR v8.1 monthly global air pollutant emissions, EDGARv81MonthlyEmis.\n\nEDGAR (Emissions Database for Global Atmospheric Research) provides global gridded emissions at 0.1°×0.1° resolution for 2000-2022. Monthly flux data (kg m⁻² s⁻¹) is available for 9 pollutants (BC, CO, NH3, NMVOC, NOx, OC, PM10, PM2.5, SO2) across multiple emission sectors.\n\nReference: Crippa, M., et al. (2024). EDGAR v8.1 Global Air Pollutant Emissions. European Commission, Joint Research Centre (JRC). https://edgar.jrc.ec.europa.eu/dataset_ap81","category":"section"},{"location":"edgar_v81/#Equations","page":"EDGAR v8.1","title":"Equations","text":"This is what its equation system looks like:\n\nusing EarthSciData, EarthSciMLBase\nusing ModelingToolkit, DynamicQuantities, DataFrames\nusing ModelingToolkit: t\nusing DynamicQuantities: dimension\nusing Dates\n\ndomain = DomainInfo(\n    DateTime(2020, 6, 1), DateTime(2020, 7, 1);\n    lonrange = deg2rad(-10.0):deg2rad(2.5):deg2rad(30.0),\n    latrange = deg2rad(40.0):deg2rad(2):deg2rad(60.0),\n    levrange = 1:10,\n)\n\nemis = EDGARv81MonthlyEmis(\"NOx\", \"POWER_INDUSTRY\", domain)","category":"section"},{"location":"edgar_v81/#Variables","page":"EDGAR v8.1","title":"Variables","text":"Here are the variables in tabular format:\n\nfunction table(vars)\n    DataFrame(\n        :Name => [string(Symbolics.tosymbol(v, escape = false)) for v in vars],\n        :Units => [dimension(ModelingToolkit.get_unit(v)) for v in vars],\n        :Description => [ModelingToolkit.getdescription(v) for v in vars]\n    )\nend\ntable(unknowns(emis))","category":"section"},{"location":"edgar_v81/#Parameters","page":"EDGAR v8.1","title":"Parameters","text":"Finally, here are the parameters in tabular format:\n\ntable(parameters(emis))","category":"section"},{"location":"edgar_v81/#EarthSciData.EDGARv81MonthlyEmis","page":"EDGAR v8.1","title":"EarthSciData.EDGARv81MonthlyEmis","text":"EDGARv81MonthlyEmis(\n    substance,\n    sector,\n    domaininfo;\n    scale,\n    name,\n    stream\n)\n\n\nA data loader for EDGAR v8.1 monthly global air pollutant emissions data at 0.1°×0.1° resolution. Data spans 2000-2022 and is available from: https://edgar.jrc.ec.europa.eu/dataset_ap81\n\nsubstance is the pollutant name (one of: BC, CO, NH3, NMVOC, NOx, OC, PM10, PM2.5, SO2).\n\nsector is the emission sector (e.g. \"POWER_INDUSTRY\", \"TRANSPORT\", \"AGRICULTURE\", etc.).\n\ndomaininfo should specify lon, lat, and lev coordinate variables.\n\nscale is a scaling factor to apply to the emissions data.\n\nstream specifies whether the data should be streamed in as needed or loaded all at once.\n\nNote: emissions are applied only at the surface level (lev < 2) and converted from flux (kg m⁻² s⁻¹) to volumetric rate (kg m⁻³ s⁻¹) by dividing by the first-layer height Δz.\n\n\n\n\n\n","category":"function"},{"location":"openaq/#OpenAQ-Air-Quality-Data","page":"OpenAQ","title":"OpenAQ Air Quality Data","text":"","category":"section"},{"location":"openaq/#Overview","page":"OpenAQ","title":"Overview","text":"OpenAQ is a global platform that aggregates and shares open air quality data from governmental and research monitoring stations worldwide. The OpenAQ data loader in EarthSciData.jl provides access to this observational data, mapping point measurements from monitoring stations onto model grid cells.\n\nData source: OpenAQ AWS S3 Archive (openaq-data-archive.s3.amazonaws.com)\n\nStation discovery: OpenAQ REST API v3 (api.openaq.org/v3)","category":"section"},{"location":"openaq/#Available-Parameters","page":"OpenAQ","title":"Available Parameters","text":"Parameter Description\npm25 Particulate matter (PM2.5)\npm10 Particulate matter (PM10)\no3 Ozone\nno2 Nitrogen dioxide\nso2 Sulfur dioxide\nco Carbon monoxide\nbc Black carbon\npm1 Particulate matter (PM1)\nno Nitric oxide\nnox Nitrogen oxides","category":"section"},{"location":"openaq/#How-It-Works","page":"OpenAQ","title":"How It Works","text":"","category":"section"},{"location":"openaq/#Data-Flow","page":"OpenAQ","title":"Data Flow","text":"Station Discovery: The OpenAQ API is queried to find all monitoring stations within the model domain's bounding box that measure the requested parameter. Results are cached locally as JSON files.\nData Download: Daily gzip-compressed CSV files are downloaded from the OpenAQ S3 archive for each station. Files are cached locally under $EARTHSCIDATADIR/openaq_data/.\nPoint-to-Grid Mapping: For each hourly time step, measurements from all stations are binned into model grid cells:\nEach station is assigned to the grid cell that contains its coordinates\nMultiple stations within the same cell are averaged\nMultiple readings from the same station within one hour are averaged\nGrid cells with no stations receive a configurable fill value (default NaN)\nUnit Conversion: OpenAQ data (typically in µg/m³) is converted to SI units (kg/m³) using the standard EarthSciData.jl unit conversion system.","category":"section"},{"location":"openaq/#Authentication","page":"OpenAQ","title":"Authentication","text":"An OpenAQ API key is required for station discovery. Set the OPENAQ_API_KEY environment variable or pass the api_key keyword argument. Sign up at explore.openaq.org.\n\nNote: No API key is needed for downloading measurement data from S3.","category":"section"},{"location":"openaq/#Station-Filtering","page":"OpenAQ","title":"Station Filtering","text":"Use the station_filter keyword argument to filter stations by any criteria:\n\n# Only include stations with \"reference\" in their name\nOpenAQ(\"pm25\", domain; station_filter = s -> occursin(\"reference\", lowercase(s.name)))\n\n# Exclude specific station IDs\nbad_ids = Set([123, 456])\nOpenAQ(\"pm25\", domain; station_filter = s -> !(s.id in bad_ids))","category":"section"},{"location":"openaq/#EarthSciData.OpenAQ","page":"OpenAQ","title":"EarthSciData.OpenAQ","text":"OpenAQ(\n    parameter,\n    domaininfo;\n    api_key,\n    station_filter,\n    fill_value,\n    name,\n    stream\n)\n\n\nCreate a ModelingToolkit System that provides interpolated OpenAQ air quality observations for the given parameter.\n\nparameter is the OpenAQ parameter name (e.g. \"pm25\", \"o3\", \"no2\").\n\ndomaininfo is a DomainInfo specifying the model domain and time span.\n\napi_key defaults to ENV[\"OPENAQ_API_KEY\"].\n\nstation_filter is a function f(::OpenAQStation) -> Bool to filter stations.\n\nfill_value is used for grid cells with no stations (default 0.0).\n\nstream specifies whether data should be streamed or loaded all at once.\n\n\n\n\n\n","category":"function"},{"location":"api/","page":"API","title":"API","text":"","category":"section"},{"location":"api/#EarthSciData._UNIT_MAP","page":"API","title":"EarthSciData._UNIT_MAP","text":"Convert a string to a DynamicQuantities.Quantity object.\n\n\n\n\n\n","category":"constant"},{"location":"api/#EarthSciData.CEDSFileSet","page":"API","title":"EarthSciData.CEDSFileSet","text":"CEDS (Community Emissions Data System) gridded emissions data.\n\nData is from the CEDS-CMIP release, providing global monthly anthropogenic emissions at 0.5° × 0.5° resolution. Each file contains one species and has dimensions (time, sector, lat, lon) with units kg m⁻² s⁻¹.\n\nReference: Hoesly et al., 2018, https://doi.org/10.5194/gmd-11-369-2018\n\nspecies specifies which emission species to load (e.g., \"SO2\"). sectors is an optional vector of sector indices (0-7) to include; nothing means sum all sectors (default).\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.DataFrequencyInfo","page":"API","title":"EarthSciData.DataFrequencyInfo","text":"Information about the temporal frequency of archived data.\n\nstart: Beginning of time of the time series.\nfrequency: Interval between each record.\ncenterpoints: Time representing the temporal center of each record.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.DataSetInterpolator","page":"API","title":"EarthSciData.DataSetInterpolator","text":"DataSetInterpolators are used to interpolate data from a FileSet to represent a given time and location. Data is loaded (and downloaded) lazily, so the first time you use it on a for a given dataset and time period it may take a while to load. Each time step is downloaded and loaded as it is needed during the simulation and cached on the hard drive at the path specified by the \\$EARTHSCIDATADIR environment variable, or in a scratch directory if that environment variable has not been specified. The interpolator will also cache data in memory representing the data records for the times immediately before and after the current time step.\n\nvarname is the name of the variable to interpolate. default_time is the time to use when initializing the interpolator. spatial_ref is the spatial reference system that the simulation will be using. stream specifies whether the data should be streamed in as needed or loaded all at once.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.EDGARv81MonthlyEmisFileSet","page":"API","title":"EarthSciData.EDGARv81MonthlyEmisFileSet","text":"EDGAR v8.1 monthly air pollutant emissions data. Global 0.1°×0.1° gridded flux data for 2000-2022.\n\nSubstances: BC, CO, NH3, NMVOC, NOx, OC, PM10, PM2.5, SO2\n\nAvailable from: https://edgar.jrc.ec.europa.eu/dataset_ap81\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.ERA5PressureLevelFileSet","page":"API","title":"EarthSciData.ERA5PressureLevelFileSet","text":"A FileSet for ERA5 reanalysis data on pressure levels from the Copernicus Climate Data Store (CDS).\n\nData is retrieved via the CDS API (requires an API key in ~/.cdsapirc or ENV[\"CDSAPI_KEY\"]) or from pre-downloaded local files (set mirror to \"file:///path/to/data\").\n\nFor local files, the expected directory structure is: {path}/era5_pl_{YYYY}_{MM}.nc where each file contains all variables for one month.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.FileSet","page":"API","title":"EarthSciData.FileSet","text":"An interface for types describing a dataset, potentially comprised of multiple files.\n\nTo satisfy this interface, a type must implement the following methods:\n\nmirror(::FileSet) (Return the base URL or path for the dataset)\nrelpath(::FileSet, ::DateTime, [varname]) (varname is optional, for per-variable file datasets)\nurl(::FileSet, ::DateTime, [varname])\nlocalpath(::FileSet, t::DateTime, [varname])\nDataFrequencyInfo(::FileSet)::DataFrequencyInfo\nloadmetadata(::FileSet, varname)::MetaData\nloadslice!(cache::AbstractArray, ::FileSet, ::DateTime, varname)\nvarnames(::FileSet)\nget_geometry(::FileSet, ::MetaData) (Returns the geometry of the data)\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.GEOSFPFileSet","page":"API","title":"EarthSciData.GEOSFPFileSet","text":"GEOS-FP data as archived for use with GEOS-Chem classic.\n\nDomain options (as of 2022-01-30):\n\n4x5\n0.125x0.15625_AS\n0.125x0.15625_EU\n0.125x0.15625_NA\n0.25x0.3125\n0.25x0.3125_AF\n0.25x0.3125_AS\n0.25x0.3125_CH\n0.25x0.3125_EU\n0.25x0.3125_ME\n0.25x0.3125_NA\n0.25x0.3125_OC\n0.25x0.3125_RU\n0.25x0.3125_SA\n0.5x0.625\n0.5x0.625_AS\n0.5x0.625_CH\n0.5x0.625_EU\n0.5x0.625_NA\n2x2.5\n4x5\nC180\nC720\nNATIVE\nc720\n\nPossible filetypes are:\n\n:A1\n:A3cld\n:A3dyn\n:A3mstC\n:A3mstE\n:I3\n\nSee http://geoschemdata.wustl.edu/ExtData/ for current options.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.GridSpec","page":"API","title":"EarthSciData.GridSpec","text":"A lightweight specification of a model grid, providing an alternative to EarthSciMLBase.DomainInfo for use cases that don't require ModelingToolkit integration.\n\ncoords: Coordinate ranges for each spatial dimension, ordered (x, y, [z]).\nspatial_ref: The spatial reference system, e.g. \"+proj=longlat +datum=WGS84 +no_defs\".\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.LANDFIREFileSet","page":"API","title":"EarthSciData.LANDFIREFileSet","text":"A FileSet for LANDFIRE (Landscape Fire and Resource Management Planning Tools) fuel model data, providing Anderson 13 or Scott & Burgan 40 fire behavior fuel model classifications at 30m resolution over the contiguous United States.\n\nData is downloaded from the LANDFIRE ImageServer REST API as GeoTIFF files. This is a static (time-invariant) dataset.\n\nThe pixel values are integer fuel model codes (e.g. 1–13 for Anderson 13, or 91=urban/developed, 92=snow/ice, 93=agriculture, 98=water, 99=barren).\n\nSee https://landfire.gov/ for more information.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.LANDFIREFileSet-Tuple{Any}","page":"API","title":"EarthSciData.LANDFIREFileSet","text":"LANDFIREFileSet(domaininfo; product, version, resolution)\n\n\nCreate a LANDFIREFileSet covering the spatial extent of the given domain.\n\nArguments\n\ndomaininfo: A DomainInfo or GridSpec providing the spatial domain.\nproduct: LANDFIRE product name (default \"FBFM13\" for Anderson 13 fuel models; use \"FBFM40\" for Scott & Burgan 40 fuel models).\nversion: LANDFIRE version (default \"LF2022\").\nresolution: Target resolution in arc-seconds (default 1.0 ≈ 30m). Note: the LANDFIRE ImageServer limits requests to 4000×4000 pixels. For large domains at fine resolution, the image will be silently downsampled.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.MetaData","page":"API","title":"EarthSciData.MetaData","text":"Information about a data array.\n\ncoords: The locations associated with each data point in the array.\nunit_str: Physical units of the data, e.g. m s⁻¹.\ndescription: Description of the data.\ndimnames: Dimensions of the data, e.g. (lat, lon, layer).\nvarsize: Dimension sizes of the data, e.g. (180, 360, 30).\nnative_sr: The spatial reference system of the data, e.g. \"+proj=longlat +datum=WGS84 +no_defs\" for lat-lon data.\nxdim: The index number of the x-dimension (e.g. longitude)\nydim: The index number of the y-dimension (e.g. latitude)\nzdim: The index number of the z-dimension (e.g. vertical level)\nstaggering: Grid staggering for each dimension. (true=edge-aligned, false=center-aligned)\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.NEI2016MonthlyEmisFileSet","page":"API","title":"EarthSciData.NEI2016MonthlyEmisFileSet","text":"Archived CMAQ emissions data.\n\nCurrently, only data for year 2016 is available.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.NetCDFOutputter","page":"API","title":"EarthSciData.NetCDFOutputter","text":"Create an EarthSciMLBase.Operator to write simulation output to a NetCDF file.\n\nfilepath::String: The path of the NetCDF file to write to\nfile::Any: The netcdf dataset\nvars::Any: The netcdf variables corresponding to the state variables\ntvar::Any: The netcdf variable for time\nh::Int64: Current time index for writing\ntime_interval::AbstractFloat: Simulation time interval (in seconds) at which to write to disk\nextra_vars::AbstractVector: Extra observed variables to write to disk\nextra_var_fs::AbstractVector: Functions to get the extra vars\ngrid::Any: Spatial grid specification\ndtype::Any: Data type of the output\ntref::Any: Reference time for the simulation, used to convert to Unix time\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.OpenAQFileSet","page":"API","title":"EarthSciData.OpenAQFileSet","text":"A FileSet for OpenAQ air quality monitoring data.\n\nData is sourced from the OpenAQ AWS S3 archive (gzip-compressed CSV files). Station locations within the model domain are discovered via the OpenAQ API and cached locally. Measurement data is downloaded from S3 (no API key needed for data download).\n\nPoint observations from monitoring stations are mapped to model grid cells by averaging all stations that fall within each cell. Grid cells with no stations receive a configurable fill value (default NaN).\n\nThe station_filter function can be used to filter stations, e.g. by name or ID. It should accept an OpenAQStation and return true to include the station.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.OpenAQFileSet-Tuple{AbstractString, Dates.DateTime, Dates.DateTime, NamedTuple{(:lon_min, :lat_min, :lon_max, :lat_max)}}","page":"API","title":"EarthSciData.OpenAQFileSet","text":"OpenAQFileSet(\n    parameter,\n    starttime,\n    endtime,\n    bbox;\n    grid_lon_edges,\n    grid_lat_edges,\n    api_key,\n    station_filter,\n    fill_value\n)\n\n\nConstruct an OpenAQFileSet for the given parameter and time range.\n\nparameter is the OpenAQ parameter name (e.g. \"pm25\", \"o3\", \"no2\").\n\nbbox is a named tuple (lon_min, lat_min, lon_max, lat_max) in degrees specifying the bounding box for station discovery.\n\napi_key is the OpenAQ API key. Defaults to ENV[\"OPENAQ_API_KEY\"].\n\nstation_filter is an optional function f(::OpenAQStation) -> Bool to filter stations. Note: station coordinates (lon, lat) are in radians when the filter is applied.\n\nfill_value is used for grid cells with no stations (default 0.0).\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.OpenAQStation","page":"API","title":"EarthSciData.OpenAQStation","text":"Information about an OpenAQ monitoring station.\n\nid: OpenAQ location ID\nname: Station name\nlon: Longitude in radians\nlat: Latitude in radians\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.TemporalCache","page":"API","title":"EarthSciData.TemporalCache","text":"Cache for time-varying interpolation state within a DataSetInterpolator.\n\ndata: The actual data array, with the last dimension being time.\ninterp_cache: Buffer used for interpolation.\nload_cache: Buffer that data is read into from file (separate from data for async loading).\nitp: The interpolation object.\ntimes: Timestamps corresponding to each time index in data.\ncurrenttime: The current time that the interpolator has been loaded for.\nloadtask: Async task for loading the next time step.\ninitialized: Whether the cache has been initialized with real data.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.USGS3DEPFileSet","page":"API","title":"EarthSciData.USGS3DEPFileSet","text":"A FileSet for USGS 3D Elevation Program (3DEP) data, providing terrain elevation at approximately 1/3 arc-second (~10m) resolution over the United States.\n\nData is downloaded from the USGS National Map ImageServer REST API as GeoTIFF files and read with TiffImages.jl. Because we control the request parameters (bounding box, output CRS, and pixel dimensions), the coordinates are computed directly from the request rather than from GeoTIFF metadata tags.\n\nThis is a static (time-invariant) dataset.\n\nSee https://elevation.nationalmap.gov/ for more information.\n\n\n\n\n\n","category":"type"},{"location":"api/#EarthSciData.USGS3DEPFileSet-Tuple{Any}","page":"API","title":"EarthSciData.USGS3DEPFileSet","text":"USGS3DEPFileSet(domaininfo; resolution)\n\n\nCreate a USGS3DEPFileSet covering the spatial extent of the given domain.\n\nwarning: US coverage only\n3DEP provides elevation data for the United States (CONUS, Alaska, Hawaii, and US territories). Requests for domains outside this coverage will return nodata values.\n\nArguments\n\ndomaininfo: A DomainInfo or GridSpec providing the spatial domain.\nresolution: Target resolution in arc-seconds (default 1/3 ≈ 10m). The pixel count is capped at 4000×4000 to avoid excessive download sizes.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.USGS3DEPSlopeFileSet","page":"API","title":"EarthSciData.USGS3DEPSlopeFileSet","text":"A FileSet that computes terrain slope from USGS 3DEP elevation data.\n\nWraps a USGS3DEPFileSet and computes the dimensionless elevation gradient in either the x (east) or y (north) direction using central finite differences on the elevation grid, with coordinate conversion from lon/lat to metric distances.\n\nThe component field selects which gradient to compute: :dzdx or :dzdy.\n\n\n\n\n\n","category":"type"},{"location":"api/#Base.close-Tuple{EarthSciData.DataSetInterpolator}","page":"API","title":"Base.close","text":"Close resources associated with a DataSetInterpolator, including the underlying FileSet.\n\n\n\n\n\n","category":"method"},{"location":"api/#Base.close-Tuple{EarthSciData.FileSet}","page":"API","title":"Base.close","text":"Close resources associated with a FileSet. Default is a no-op. Concrete subtypes with open file handles should override this.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.CEDS-Tuple{EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.CEDS","text":"CEDS(\n    domaininfo;\n    species,\n    sectors,\n    mirror,\n    version,\n    data_version,\n    name,\n    stream\n)\n\n\nA data loader for CEDS (Community Emissions Data System) global gridded anthropogenic emissions.\n\nCEDS provides monthly emissions at 0.5° × 0.5° resolution from 1750 to 2023 in units of kg m⁻² s⁻¹, with 8 anthropogenic sectors.\n\nReference: Hoesly et al., 2018, https://doi.org/10.5194/gmd-11-369-2018\n\nAvailable species: BC, CH4, CO, CO2, N2O, NH3, NMVOC, NOx, OC, SO2.\n\nSectors (0-7): 0: Agriculture; 1: Energy; 2: Industrial; 3: Transportation; 4: Residential, Commercial, Other; 5: Solvents production and application; 6: Waste; 7: International Shipping.\n\nKeyword Arguments\n\nspecies: Vector of species to load. Default is all: [\"BC\", \"CH4\", \"CO\", \"CO2\", \"N2O\", \"NH3\", \"NMVOC\", \"NOx\", \"OC\", \"SO2\"].\nsectors: Vector of sector indices (0-7) to include, or nothing for all (default).\nmirror: Base URL for data download. Default is the ORNL ESGF THREDDS server.\nversion: CEDS source version. Default is \"CEDS-CMIP-2025-04-18\".\ndata_version: Data version string. Default is \"v20250421\".\nname: System name. Default is :CEDS.\nstream: Whether to stream data on demand. Default is true.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.EDGARv81MonthlyEmis-Tuple{AbstractString, AbstractString, EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.EDGARv81MonthlyEmis","text":"EDGARv81MonthlyEmis(\n    substance,\n    sector,\n    domaininfo;\n    scale,\n    name,\n    stream\n)\n\n\nA data loader for EDGAR v8.1 monthly global air pollutant emissions data at 0.1°×0.1° resolution. Data spans 2000-2022 and is available from: https://edgar.jrc.ec.europa.eu/dataset_ap81\n\nsubstance is the pollutant name (one of: BC, CO, NH3, NMVOC, NOx, OC, PM10, PM2.5, SO2).\n\nsector is the emission sector (e.g. \"POWER_INDUSTRY\", \"TRANSPORT\", \"AGRICULTURE\", etc.).\n\ndomaininfo should specify lon, lat, and lev coordinate variables.\n\nscale is a scaling factor to apply to the emissions data.\n\nstream specifies whether the data should be streamed in as needed or loaded all at once.\n\nNote: emissions are applied only at the surface level (lev < 2) and converted from flux (kg m⁻² s⁻¹) to volumetric rate (kg m⁻³ s⁻¹) by dividing by the first-layer height Δz.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.ERA5-Tuple{EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.ERA5","text":"ERA5(domaininfo; name, mirror, variables, stream)\n\n\nA data loader for ERA5 reanalysis data on pressure levels from the Copernicus Climate Data Store (CDS).\n\nERA5 is the fifth generation ECMWF atmospheric reanalysis of the global climate, covering 1940 to present with hourly temporal resolution and 0.25deg x 0.25deg spatial resolution on 37 pressure levels.\n\nAuthentication: Requires a CDS API key. Either:\n\nSet ENV[\"CDSAPI_KEY\"]\nCreate ~/.cdsapirc with url: https://cds.climate.copernicus.eu/api and key: <your-key>\n\nPre-downloaded data: Pass mirror=\"file:///path/to/data\" to use local NetCDF files. Expected filenames: era5_pl_YYYY_MM.nc containing all variables for that month.\n\nAvailable variables (all on pressure levels): temperature, u/v wind, vertical velocity, specific/relative humidity, geopotential, divergence, vorticity, ozone, cloud fractions, potential vorticity.\n\nThe native data type for this dataset is Float32.\n\nstream specifies whether the data should be streamed in as needed or loaded all at once.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.GEOSFP-Tuple{AbstractString, EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.GEOSFP","text":"GEOSFP(domain, domaininfo; name, stream)\n\n\nA data loader for GEOS-FP data as archived for use with GEOS-Chem classic.\n\nDomain options (as of 2022-01-30):\n\n4x5\n0.125x0.15625_AS\n0.125x0.15625_EU\n0.125x0.15625_NA\n0.25x0.3125\n0.25x0.3125_AF\n0.25x0.3125_AS\n0.25x0.3125_CH\n0.25x0.3125_EU\n0.25x0.3125_ME\n0.25x0.3125_NA\n0.25x0.3125_OC\n0.25x0.3125_RU\n0.25x0.3125_SA\n0.5x0.625\n0.5x0.625_AS\n0.5x0.625_CH\n0.5x0.625_EU\n0.5x0.625_NA\n2x2.5\n4x5\nC180\nC720\nNATIVE\nc720\n\nThe native data type for this dataset is Float32.\n\nstream specifies whether the data should be streamed in as needed or loaded all at once.\n\nSee http://geoschemdata.wustl.edu/ExtData/ for current data domain options.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.LANDFIRE-Tuple{EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.LANDFIRE","text":"LANDFIRE(\n    domaininfo;\n    name,\n    product,\n    version,\n    resolution,\n    stream\n)\n\n\nCreate a ModelingToolkit System that provides fuel model data from LANDFIRE.\n\nThe system exposes a single variable fuel_model (dimensionless) interpolated to the simulation coordinates using nearest-neighbour interpolation (appropriate for categorical data).\n\nArguments\n\ndomaininfo: A DomainInfo specifying the spatial and temporal domain.\nname: System name (default :LANDFIRE).\nproduct: LANDFIRE product (default \"FBFM13\" for Anderson 13 fuel models).\nversion: LANDFIRE version (default \"LF2022\").\nresolution: Target resolution in arc-seconds (default 1.0 ≈ 30m).\nstream: Whether to stream data lazily (default true).\n\nExample\n\nusing EarthSciData, EarthSciMLBase, ModelingToolkit, Dates\ndomain = DomainInfo(\n    DateTime(2018, 11, 8), DateTime(2018, 11, 9);\n    lonrange = deg2rad(-121.7):deg2rad(0.01):deg2rad(-121.5),\n    latrange = deg2rad(39.7):deg2rad(0.01):deg2rad(39.8),\n    levrange = 1:1\n)\nfuel = LANDFIRE(domain)\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.NEI2016MonthlyEmis-Tuple{AbstractString, EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.NEI2016MonthlyEmis","text":"NEI2016MonthlyEmis(sector, domaininfo; scale, name, stream)\n\n\nA data loader for CMAQ-formatted monthly US National Emissions Inventory data for year 2016, available from: https://gaftp.epa.gov/Air/emismod/2016/v1/gridded/monthly_netCDF/. The emissions here are monthly averages, so there is no information about diurnal variation etc.\n\nThe emissions are returned as mixing ratios in units of kg/kg/s by converting from the native flux density (kg/m²/s) using:\n\nmixing_ratio = flux / (g0_100 * delp_dry_surface)\n\nwhere g0100 ≈ 10.197 kg/m² and delpdry_surface is the dry pressure thickness (physically unit in hPa, but here is unitless) that varies spatially across the domain.\n\nscale is a scaling factor to apply to the emissions data. The default value is 1.0.\n\nstream specifies whether the data should be streamed in as needed or loaded all at once.\n\nConservative regridding (via ConservativeRegridding.jl) is used by default to map emissions from the native NEI Lambert Conformal Conic grid to the simulation domain grid, preserving total emissions mass.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.OpenAQ-Tuple{AbstractString, EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.OpenAQ","text":"OpenAQ(\n    parameter,\n    domaininfo;\n    api_key,\n    station_filter,\n    fill_value,\n    name,\n    stream\n)\n\n\nCreate a ModelingToolkit System that provides interpolated OpenAQ air quality observations for the given parameter.\n\nparameter is the OpenAQ parameter name (e.g. \"pm25\", \"o3\", \"no2\").\n\ndomaininfo is a DomainInfo specifying the model domain and time span.\n\napi_key defaults to ENV[\"OPENAQ_API_KEY\"].\n\nstation_filter is a function f(::OpenAQStation) -> Bool to filter stations.\n\nfill_value is used for grid cells with no stations (default 0.0).\n\nstream specifies whether data should be streamed or loaded all at once.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.USGS3DEP-Tuple{EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.USGS3DEP","text":"USGS3DEP(domaininfo; name, resolution, stream)\n\n\nCreate a ModelingToolkit System that provides terrain elevation and slope data from the USGS 3D Elevation Program (3DEP).\n\nThe system exposes three variables interpolated to the simulation coordinates:\n\nelevation (m): terrain elevation above sea level\ndzdx (dimensionless): terrain slope in the x (east) direction (rise/run)\ndzdy (dimensionless): terrain slope in the y (north) direction (rise/run)\n\nSlopes are computed from the elevation grid using central finite differences with coordinate conversion from lon/lat to metric distances.\n\nThe domain may use any coordinate reference system (lon-lat, UTM, Lambert Conformal Conic, etc.). The domain bounding box is automatically reprojected to WGS84 for the USGS API request, and coordinate transforms between the domain CRS and the data's native lon-lat grid are handled by the interpolation infrastructure.\n\nNote that 3DEP coverage is limited to the United States (CONUS, Alaska, Hawaii, and US territories).\n\nArguments\n\ndomaininfo: A DomainInfo specifying the spatial and temporal domain.\nname: System name (default :USGS3DEP).\nresolution: Target resolution in arc-seconds (default 1/3 ≈ 10m).\nstream: Whether to stream data lazily (default true).\n\nExample\n\nusing EarthSciData, EarthSciMLBase, ModelingToolkit, Dates\ndomain = DomainInfo(\n    DateTime(2018, 11, 8), DateTime(2018, 11, 9);\n    lonrange = deg2rad(-121.7):deg2rad(0.01):deg2rad(-121.5),\n    latrange = deg2rad(39.7):deg2rad(0.01):deg2rad(39.8),\n    levrange = 1:1,\n)\nelev = USGS3DEP(domain)\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._build_cell_station_map-Tuple{Vector{EarthSciData.OpenAQStation}, Vector{Float64}, Vector{Float64}}","page":"API","title":"EarthSciData._build_cell_station_map","text":"Build a mapping from (i, j) grid cell indices to vectors of station indices. Grid edges are in radians.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._ceds_chunk_for_year-Tuple{Int64}","page":"API","title":"EarthSciData._ceds_chunk_for_year","text":"_ceds_chunk_for_year(year)\n\n\nReturn the CEDS file time chunk (startyear, endyear) that contains the given year.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._domain_bbox_wgs84-Tuple{Any}","page":"API","title":"EarthSciData._domain_bbox_wgs84","text":"Compute the WGS84 bounding box (west, south, east, north) in degrees for the given domain, handling arbitrary projections.\n\nFor longlat domains the grid extrema are converted from radians to degrees. For projected domains (e.g. LCC) every point along the four edges of the domain rectangle is transformed to WGS84 and the envelope is returned.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._download_with_progress-Tuple{AbstractString, AbstractString}","page":"API","title":"EarthSciData._download_with_progress","text":"Download a file with a progress bar, deleting the partial file on error.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._load_station_day-Tuple{EarthSciData.OpenAQFileSet, Int64, Dates.Date}","page":"API","title":"EarthSciData._load_station_day","text":"Load and cache parsed rows for a station's daily CSV file, filtered to the FileSet's parameter. Returns a vector of (datetime_utc, value) tuples. The cache is scoped to the OpenAQFileSet instance and protected by a lock.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._match_domain_coords-Tuple{Any, Any, Any}","page":"API","title":"EarthSciData._match_domain_coords","text":"Map data dimension names to domain coordinate variables.\n\nFor lon-lat domains the mapping is direct (lon→lon, lat→lat). For projected domains where the domain has x and y variables, lon maps to x and lat maps to y.  The coordinate transform between the domain CRS and the data CRS is handled by coord_trans inside DataSetInterpolator.\n\nAccepts both String and Symbol dimension names.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._nearest_interpolate_from!-Union{Tuple{T}, Tuple{AbstractMatrix{T}, AbstractMatrix{T}, EarthSciData.MetaData, Any, Any}} where T","page":"API","title":"EarthSciData._nearest_interpolate_from!","text":"Nearest-neighbour version of interpolate_from!, suitable for categorical (integer-valued) data such as fuel model codes.  Uses BSpline(Constant()) instead of BSpline(Linear()).\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._parse_openaq_datetime-Tuple{AbstractString}","page":"API","title":"EarthSciData._parse_openaq_datetime","text":"Parse an OpenAQ datetime string, converting timezone offsets to UTC. Supports formats: \"2024-01-15T12:00:00+00:00\", \"2024-01-15T12:00:00Z\", \"2024-01-15T12:00:00\".\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData._read_station_hour-Tuple{EarthSciData.OpenAQFileSet, Int64, Dates.Date, Dates.DateTime, Dates.DateTime}","page":"API","title":"EarthSciData._read_station_hour","text":"Read measurements for a single station for a single hour. Returns (total, count) for computing an average. Uses cached daily data to avoid repeated decompression.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.affect!-Tuple{NetCDFOutputter, Any}","page":"API","title":"EarthSciData.affect!","text":"Write the current state of the system to the NetCDF file.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.cds_api_key-Tuple{}","page":"API","title":"EarthSciData.cds_api_key","text":"cds_api_key()\n\n\nRead the CDS API key from ENV[\"CDSAPI_KEY\"] or ~/.cdsapirc.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.cds_retrieve-Tuple{AbstractString, Dict, AbstractString}","page":"API","title":"EarthSciData.cds_retrieve","text":"cds_retrieve(dataset, request, output_path; api_key)\n\n\nSubmit a CDS API request, wait for completion, and download the result. Returns the local file path.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.cds_submit-Tuple{AbstractString, Dict}","page":"API","title":"EarthSciData.cds_submit","text":"cds_submit(dataset, request; api_key)\n\n\nSubmit a CDS API retrieve request and return the job ID. dataset is the CDS dataset identifier (e.g. \"reanalysis-era5-pressure-levels\"). request is a Dict with the request parameters.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.cds_wait-Tuple{AbstractString}","page":"API","title":"EarthSciData.cds_wait","text":"cds_wait(job_id; api_key, poll_interval, timeout)\n\n\nPoll a CDS API job until completion. Returns the download URL.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.centerpoint_index-Tuple{EarthSciData.DataFrequencyInfo, Dates.DateTime}","page":"API","title":"EarthSciData.centerpoint_index","text":"Return the index of the centerpoint closest to the given time.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.create_interp_equation-Tuple{EarthSciData.DataSetInterpolator, Vararg{Any, 4}}","page":"API","title":"EarthSciData.create_interp_equation","text":"create_interp_equation(\n    itp,\n    filename,\n    t,\n    t_ref,\n    coords;\n    wrapper_f\n)\n\n\nCreate an equation that interpolates the given dataset at the given time and location. filename is an identifier for the dataset, and t is the time variable. wrapper_f can specify a function to wrap the interpolated value, for example eq -> eq / 2 to divide the interpolated value by 2.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.create_interpolator!-NTuple{4, Any}","page":"API","title":"EarthSciData.create_interpolator!","text":"Create a new interpolator, overwriting interp_cache.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.currenttimepoint-Tuple{EarthSciData.DataSetInterpolator, Dates.DateTime}","page":"API","title":"EarthSciData.currenttimepoint","text":"Return the current interpolation time point for this interpolator.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.data2vecormat-Union{Tuple{T}, Tuple{AbstractArray{T, 3}, Any, Any}} where T","page":"API","title":"EarthSciData.data2vecormat","text":"Convert an N-D array to a 2-D matrix with where the horizontal dimensions are rows and the vertical dimension is the columns. If the input is 2-D, it is converted to a vector.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.dayofweek_itp_CO-Tuple{Any, Any}","page":"API","title":"EarthSciData.dayofweek_itp_CO","text":"dayofweek_itp_CO(t, lon)\n\n\nDay of week interpolation function that returns the scale factor for a given time. Returns different emission scaling factors based on the day of week.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.delp_dry_surface_itp-Tuple{Any, Any}","page":"API","title":"EarthSciData.delp_dry_surface_itp","text":"delp_dry_surface_itp(lon, lat)\n\n\nInterpolate the delpdrysurface field at a given longitude and latitude. Returns the dry pressure thickness value in Pa.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.description-Tuple{EarthSciData.DataSetInterpolator}","page":"API","title":"EarthSciData.description","text":"description(itp)\n\n\nReturn the description of the data associated with this interpolator.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.dimnames-Tuple{EarthSciData.DataSetInterpolator}","page":"API","title":"EarthSciData.dimnames","text":"dimnames(itp)\n\n\nReturn the dimension names associated with this interpolator.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.discover_stations-Tuple{AbstractString, NamedTuple{(:lon_min, :lat_min, :lon_max, :lat_max)}, AbstractString, Function}","page":"API","title":"EarthSciData.discover_stations","text":"discover_stations(parameter, bbox, api_key, station_filter)\n\n\nDiscover OpenAQ stations within the given bounding box for the specified parameter. Uses the OpenAQ v3 API with pagination. Results are cached locally. bbox values are in degrees.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.diurnal_itp-Tuple{Any, Any}","page":"API","title":"EarthSciData.diurnal_itp","text":"diurnal_itp(t, lon)\n\n\nDiurnal interpolation function that returns the scale factor for a given time. Returns different emission scaling factors based on the hour of day.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.download_station_data-Tuple{Vector{EarthSciData.OpenAQStation}, Dates.DateTime, Dates.DateTime}","page":"API","title":"EarthSciData.download_station_data","text":"download_station_data(stations, starttime, endtime)\n\n\nDownload daily CSV.gz files from the OpenAQ S3 archive for the given stations and time range.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.endpoints-Tuple{EarthSciData.DataFrequencyInfo}","page":"API","title":"EarthSciData.endpoints","text":"Return the time endpoints corresponding to each centerpoint\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.get_tstops-Tuple{EarthSciData.DataSetInterpolator, Dates.DateTime}","page":"API","title":"EarthSciData.get_tstops","text":"The time points when integration should be stopped to update the interpolator (as Unix timestamps).\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.interp-Union{Tuple{N2}, Tuple{N}, Tuple{T}, Tuple{EarthSciData.DataSetInterpolator{T, N, N2}, Dates.DateTime, Vararg{T, N2}}} where {T, N, N2}","page":"API","title":"EarthSciData.interp","text":"interp(itp, t, locs)\n\n\nReturn the value of the given variable from the given dataset at the given time and location.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.interp-Union{Tuple{N}, Tuple{T}, Tuple{EarthSciData.DataSetInterpolator, Real, Vararg{T, N}}} where {T, N}","page":"API","title":"EarthSciData.interp","text":"Interpolation with a unix timestamp.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.interp_cache_times!-Tuple{EarthSciData.DataSetInterpolator, Dates.DateTime}","page":"API","title":"EarthSciData.interp_cache_times!","text":"Load the time points that should be cached in this interpolator.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.interp_unsafe-Union{Tuple{N2}, Tuple{N}, Tuple{T2}, Tuple{T1}, Tuple{EarthSciData.DataSetInterpolator{T1, N, N2}, Dates.DateTime, Vararg{T2, N2}}} where {T1, T2, N, N2}","page":"API","title":"EarthSciData.interp_unsafe","text":"Interpolate without checking if the data has been correctly loaded for the given time.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.knots2range","page":"API","title":"EarthSciData.knots2range","text":"Convert a vector of evenly spaced grid points to a range. The reltol parameter specifies the relative tolerance for the grid spacing, which is necessary to account for different numbers of days in each month and things like that.\n\n\n\n\n\n","category":"function"},{"location":"api/#EarthSciData.loadmetadata-Tuple{EarthSciData.CEDSFileSet, Any}","page":"API","title":"EarthSciData.loadmetadata","text":"loadmetadata(fs, varname)\n\n\nLoad metadata for the given variable in the CEDS dataset.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.loadmetadata-Tuple{EarthSciData.EDGARv81MonthlyEmisFileSet, Any}","page":"API","title":"EarthSciData.loadmetadata","text":"loadmetadata(fs, varname)\n\n\nLoad metadata for the given variable.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.loadmetadata-Tuple{EarthSciData.GEOSFPFileSet, Any}","page":"API","title":"EarthSciData.loadmetadata","text":"loadmetadata(fs, varname)\n\n\nLoad the data for the given variable name at the given time.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.loadmetadata-Tuple{EarthSciData.NEI2016MonthlyEmisFileSet, Any}","page":"API","title":"EarthSciData.loadmetadata","text":"loadmetadata(fs, varname)\n\n\nLoad the data for the given variable name at the given time.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.loadslice!-Tuple{AbstractArray, EarthSciData.CEDSFileSet, Dates.DateTime, Any}","page":"API","title":"EarthSciData.loadslice!","text":"loadslice!(data, fs, t, varname)\n\n\nLoad a time slice from the CEDS dataset, summing across sectors (or filtering by selected sectors). The result is a 2D (lat, lon) array in kg m⁻² s⁻¹.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.loadslice!-Tuple{AbstractArray, EarthSciData.EDGARv81MonthlyEmisFileSet, Dates.DateTime, Any}","page":"API","title":"EarthSciData.loadslice!","text":"loadslice!(data, fs, t, varname)\n\n\nLoad the data in place for the given variable name at the given time.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.loadslice!-Tuple{AbstractArray, EarthSciData.GEOSFPFileSet, Dates.DateTime, Any}","page":"API","title":"EarthSciData.loadslice!","text":"loadslice!(data, fs, t, varname)\n\n\nLoad the data in place for the given variable name at the given time.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.loadslice!-Tuple{AbstractArray, EarthSciData.NEI2016MonthlyEmisFileSet, Dates.DateTime, Any}","page":"API","title":"EarthSciData.loadslice!","text":"loadslice!(data, fs, t, varname)\n\n\nLoad the NEI data for the given variable name at the given time. This loads data in kg/s/m^2 units on the NEI source grid for regridding.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.loadslice!-Tuple{AbstractArray, EarthSciData.OpenAQFileSet, Dates.DateTime, String}","page":"API","title":"EarthSciData.loadslice!","text":"loadslice!(data, fs, t, varname)\n\n\nLoad OpenAQ measurement data for the given time into data. Data is binned onto the grid by averaging all stations within each cell.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.localpath","page":"API","title":"EarthSciData.localpath","text":"localpath(fs, t)\nlocalpath(fs, t, varname)\n\n\nReturn the local path for the file for the given DateTime. An optional varname can be provided for datasets with per-variable files.\n\n\n\n\n\n","category":"function"},{"location":"api/#EarthSciData.localpath-2","page":"API","title":"EarthSciData.localpath","text":"localpath(fs, t)\nlocalpath(fs, t, varname)\n\n\nLocal cache path for CEDS data files, using a short directory structure to avoid exceeding Windows' 260-character MAX_PATH limit.\n\n\n\n\n\n","category":"function"},{"location":"api/#EarthSciData.maybedownload","page":"API","title":"EarthSciData.maybedownload","text":"maybedownload(fs, t)\nmaybedownload(fs, t, varname)\n\n\nCheck if the specified file exists locally. If not, download it. An optional varname can be provided for datasets with per-variable files.\n\n\n\n\n\n","category":"function"},{"location":"api/#EarthSciData.mirror-Tuple{EarthSciData.FileSet}","page":"API","title":"EarthSciData.mirror","text":"mirror(fs)\n\n\nReturn the base URL or path for the dataset.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.nexttimepoint-Tuple{EarthSciData.DataSetInterpolator, Dates.DateTime}","page":"API","title":"EarthSciData.nexttimepoint","text":"Return the next interpolation time point for this interpolator.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.partialderivatives_δPδlev_era5-Tuple{}","page":"API","title":"EarthSciData.partialderivatives_δPδlev_era5","text":"partialderivatives_δPδlev_era5(; default_lev)\n\n\nReturn a function to calculate coefficients to multiply the δ(u)/δ(lev) partial derivative operator by to convert from δ(u)/δ(lev) to δ(u)/δ(P), i.e. from vertical level index to pressure in Pa.\n\nUsage (mirrors the GEOSFP pattern):\n\nera5 = ERA5(domain; ...)\ndomain2 = EarthSciMLBase.add_partial_derivative_func(\n    domain,\n    partialderivatives_δPδlev_era5(),\n)\ncomposed = couple(sys, domain2, Advection(), era5)\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.partialderivatives_δPδlev_geosfp-Tuple{Any}","page":"API","title":"EarthSciData.partialderivatives_δPδlev_geosfp","text":"partialderivatives_δPδlev_geosfp(geosfp; default_lev)\n\n\nReturn a function to calculate coefficients to multiply the δ(u)/δ(lev) partial derivative operator by to convert a variable named u from δ(u)/δ(lev)toδ(u)/δ(P), i.e. from vertical level number to pressure in hPa. The return format iscoordinateindex => conversionfactor`.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.prevtimepoint-Tuple{EarthSciData.DataSetInterpolator, Dates.DateTime}","page":"API","title":"EarthSciData.prevtimepoint","text":"Return the previous interpolation time point for this interpolator.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.regridder-Tuple{EarthSciData.FileSet, EarthSciData.MetaData, EarthSciMLBase.DomainInfo}","page":"API","title":"EarthSciData.regridder","text":"Create a regridding function for the given file set, metadata, and domain. If any dimensions are staggered, use interpolation; otherwise, use conservative regridding. extrapolate_type specifies the extrapolation method for interpolation; it is only used when interpolation is selected.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.relpath-Tuple{EarthSciData.CEDSFileSet, Dates.DateTime}","page":"API","title":"EarthSciData.relpath","text":"relpath(fs, t)\n\n\nFile path on the server relative to the mirror root; also used for local caching. The t parameter determines which 50-year chunk file to select.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.relpath-Tuple{EarthSciData.EDGARv81MonthlyEmisFileSet, Dates.DateTime}","page":"API","title":"EarthSciData.relpath","text":"relpath(fs, t)\n\n\nFile path on the server relative to the host root. For EDGAR, this returns the zip file path (all times are in one archive).\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.relpath-Tuple{EarthSciData.FileSet, Dates.DateTime, Nothing}","page":"API","title":"EarthSciData.relpath","text":"Default 3-argument relpath falls back to the 2-argument version, ignoring varname. Subtypes with per-variable files should override this.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.relpath-Tuple{EarthSciData.GEOSFPFileSet, Dates.DateTime}","page":"API","title":"EarthSciData.relpath","text":"relpath(fs, t)\n\n\nFile path on the server relative to the host root; also path on local disk relative to ENV[\"EARTHSCIDATADIR\"] (or a scratch directory if that environment variable is not set).\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.relpath-Tuple{EarthSciData.NEI2016MonthlyEmisFileSet, Dates.DateTime}","page":"API","title":"EarthSciData.relpath","text":"relpath(fs, t)\n\n\nFile path on the server relative to the host root; also path on local disk relative to ENV[\"EARTHSCIDATADIR\"].\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.units-Tuple{EarthSciData.DataSetInterpolator}","page":"API","title":"EarthSciData.units","text":"units(itp)\n\n\nReturn the units of the data associated with this interpolator.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.url","page":"API","title":"EarthSciData.url","text":"url(fs, t)\nurl(fs, t, varname)\n\n\nReturn the URL for the file for the given DateTime. An optional varname can be provided for datasets with per-variable files.\n\n\n\n\n\n","category":"function"},{"location":"api/#EarthSciData.varnames-Tuple{EarthSciData.CEDSFileSet}","page":"API","title":"EarthSciData.varnames","text":"varnames(fs)\n\n\nReturn the variable names for this CEDS FileSet.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.varnames-Tuple{EarthSciData.EDGARv81MonthlyEmisFileSet}","page":"API","title":"EarthSciData.varnames","text":"varnames(fs)\n\n\nReturn the variable names associated with this FileSet.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.varnames-Tuple{EarthSciData.GEOSFPFileSet}","page":"API","title":"EarthSciData.varnames","text":"varnames(fs)\n\n\nReturn the variable names associated with this FileSet.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.varnames-Tuple{EarthSciData.NEI2016MonthlyEmisFileSet}","page":"API","title":"EarthSciData.varnames","text":"varnames(fs)\n\n\nReturn the variable names associated with this FileSet.\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciData.verify_fileset_interface-Union{Tuple{Type{T}}, Tuple{T}} where T<:EarthSciData.FileSet","page":"API","title":"EarthSciData.verify_fileset_interface","text":"verify_fileset_interface(_)\n\n\nCheck that type T implements all required FileSet interface methods. Throws an error listing any missing methods. This is an opt-in check intended for use when implementing a new FileSet subtype.\n\nExample\n\nstruct MyFileSet <: EarthSciData.FileSet ... end\n# After defining all methods:\nEarthSciData.verify_fileset_interface(MyFileSet)\n\n\n\n\n\n","category":"method"},{"location":"api/#EarthSciMLBase.init_callback-Tuple{NetCDFOutputter, EarthSciMLBase.CoupledSystem, Any, Any, EarthSciMLBase.DomainInfo, EarthSciMLBase.MapAlgorithm}","page":"API","title":"EarthSciMLBase.init_callback","text":"Set up the output file and the callback function.\n\n\n\n\n\n","category":"method"},{"location":"api/#ModelingToolkitBase.get_unit-Tuple{EarthSciData.DataSetInterpolator}","page":"API","title":"ModelingToolkitBase.get_unit","text":"Return the units of the data.\n\n\n\n\n\n","category":"method"},{"location":"nei2016/#2016-US-EPA-National-Emissions-Inventory-(NEI)-data","page":"2016 NEI","title":"2016 US EPA National Emissions Inventory (NEI) data","text":"We have a data loader for CMAQ-formatted monthly US National Emissions Inventory data for year 2016,NEI2016MonthlyEmis.","category":"section"},{"location":"nei2016/#Download-Configuration","page":"2016 NEI","title":"Download Configuration","text":"Because there is an issue with the EPA's FTP server that we download the data from you may need to set the following environment variable before using it:\n\nIn Julia:\n\nENV[\"JULIA_NO_VERIFY_HOSTS\"] = \"gaftp.epa.gov\"\n\nor in a bash shell:\n\nexport JULIA_NO_VERIFY_HOSTS=gaftp.epa.gov","category":"section"},{"location":"nei2016/#Equations","page":"2016 NEI","title":"Equations","text":"This is what its equation system looks like:\n\nusing EarthSciData, EarthSciMLBase\nusing ModelingToolkit, DynamicQuantities, DataFrames\nusing ModelingToolkit: t\nusing DynamicQuantities: dimension\nusing Dates\n\ndomain = DomainInfo(\n    DateTime(2016, 5, 1), DateTime(2016, 5, 2);\n    lonrange = deg2rad(-115):deg2rad(2.5):deg2rad(-68.75),\n    latrange = deg2rad(25):deg2rad(2):deg2rad(53.7),\n    levrange = 1:10,\n    u_proto = zeros(Float32, 1, 1, 1, 1)\n)\n\nemis = NEI2016MonthlyEmis(\"mrggrid_withbeis_withrwc\", domain)","category":"section"},{"location":"nei2016/#Variables","page":"2016 NEI","title":"Variables","text":"Here are the variables in tabular format:\n\nfunction table(vars)\n    DataFrame(\n        :Name => [string(Symbolics.tosymbol(v, escape = false)) for v in vars],\n        :Units => [dimension(ModelingToolkit.get_unit(v)) for v in vars],\n        :Description => [ModelingToolkit.getdescription(v) for v in vars]\n    )\nend\ntable(unknowns(emis))","category":"section"},{"location":"nei2016/#Parameters","page":"2016 NEI","title":"Parameters","text":"Finally, here are the parameters in tabular format:\n\ntable(parameters(emis))","category":"section"},{"location":"usgs3dep/#USGS-3DEP-Elevation-Data","page":"USGS 3DEP","title":"USGS 3DEP Elevation Data","text":"","category":"section"},{"location":"usgs3dep/#Overview","page":"USGS 3DEP","title":"Overview","text":"The USGS 3D Elevation Program (3DEP) provides high-resolution terrain elevation data for the United States (CONUS, Alaska, Hawaii, and US territories). The default resolution is 1/3 arc-second (~10m).\n\nData is downloaded on-demand from the USGS National Map ImageServer REST API as GeoTIFF tiles and read with TiffImages.jl (no GDAL dependency required). This is a static (time-invariant) dataset – the elevation values do not change over the simulation time span.","category":"section"},{"location":"usgs3dep/#Usage","page":"USGS 3DEP","title":"Usage","text":"using EarthSciData, EarthSciMLBase\nusing ModelingToolkit, DataFrames\nusing ModelingToolkit: t\nusing Dates\nusing DynamicQuantities\nusing DynamicQuantities: dimension\n\n# Define a domain near Paradise, CA\ndomain = DomainInfo(\n    DateTime(2018, 11, 8), DateTime(2018, 11, 9);\n    lonrange = deg2rad(-121.7):deg2rad(0.01):deg2rad(-121.5),\n    latrange = deg2rad(39.7):deg2rad(0.01):deg2rad(39.8),\n    levrange = 1:1,\n)\n\nelev = USGS3DEP(domain; resolution=10.0)","category":"section"},{"location":"usgs3dep/#Variables","page":"USGS 3DEP","title":"Variables","text":"vars = unknowns(elev)\nDataFrame(\n    :Name => [string(Symbolics.tosymbol(v, escape = false)) for v in vars],\n    :Units => [dimension(ModelingToolkit.get_unit(v)) for v in vars],\n    :Description => [ModelingToolkit.getdescription(v) for v in vars]\n)","category":"section"},{"location":"usgs3dep/#Parameters","page":"USGS 3DEP","title":"Parameters","text":"function table(vars)\n    DataFrame(\n        :Name => [string(Symbolics.tosymbol(v, escape = false)) for v in vars],\n        :Units => [dimension(ModelingToolkit.get_unit(v)) for v in vars],\n        :Description => [ModelingToolkit.getdescription(v) for v in vars]\n    )\nend\ntable(parameters(elev))","category":"section"},{"location":"usgs3dep/#Equations","page":"USGS 3DEP","title":"Equations","text":"eqs = equations(elev)","category":"section"},{"location":"usgs3dep/#How-It-Works","page":"USGS 3DEP","title":"How It Works","text":"Bounding box: The spatial extent of the domain is converted to a WGS84 (EPSG:4326) longitude/latitude bounding box with a one-pixel buffer.\nDownload: A single GeoTIFF tile covering the bounding box is requested from the USGS ImageServer exportImage endpoint. Pixel dimensions are computed from the requested resolution, capped at 4000x4000 to limit download size. The tile is cached locally.\nCoordinate mapping: Pixel-centre coordinates are computed analytically from the bounding box and pixel dimensions (no GeoTIFF metadata parsing needed). Coordinates are stored in radians for consistency with the EarthSciML coordinate system.\nInterpolation: The elevation field is provided as a DataSetInterpolator that maps simulation coordinates to elevation values via bilinear interpolation.","category":"section"},{"location":"usgs3dep/#Coverage","page":"USGS 3DEP","title":"Coverage","text":"warning: US coverage only\n3DEP provides elevation data for the United States only. If the domain falls outside US coverage, a warning is issued and the returned data may contain nodata values. Approximate coverage bounds: longitude -180 to -60, latitude 17 to 72.","category":"section"},{"location":"usgs3dep/#EarthSciData.USGS3DEP","page":"USGS 3DEP","title":"EarthSciData.USGS3DEP","text":"USGS3DEP(domaininfo; name, resolution, stream)\n\n\nCreate a ModelingToolkit System that provides terrain elevation and slope data from the USGS 3D Elevation Program (3DEP).\n\nThe system exposes three variables interpolated to the simulation coordinates:\n\nelevation (m): terrain elevation above sea level\ndzdx (dimensionless): terrain slope in the x (east) direction (rise/run)\ndzdy (dimensionless): terrain slope in the y (north) direction (rise/run)\n\nSlopes are computed from the elevation grid using central finite differences with coordinate conversion from lon/lat to metric distances.\n\nThe domain may use any coordinate reference system (lon-lat, UTM, Lambert Conformal Conic, etc.). The domain bounding box is automatically reprojected to WGS84 for the USGS API request, and coordinate transforms between the domain CRS and the data's native lon-lat grid are handled by the interpolation infrastructure.\n\nNote that 3DEP coverage is limited to the United States (CONUS, Alaska, Hawaii, and US territories).\n\nArguments\n\ndomaininfo: A DomainInfo specifying the spatial and temporal domain.\nname: System name (default :USGS3DEP).\nresolution: Target resolution in arc-seconds (default 1/3 ≈ 10m).\nstream: Whether to stream data lazily (default true).\n\nExample\n\nusing EarthSciData, EarthSciMLBase, ModelingToolkit, Dates\ndomain = DomainInfo(\n    DateTime(2018, 11, 8), DateTime(2018, 11, 9);\n    lonrange = deg2rad(-121.7):deg2rad(0.01):deg2rad(-121.5),\n    latrange = deg2rad(39.7):deg2rad(0.01):deg2rad(39.8),\n    levrange = 1:1,\n)\nelev = USGS3DEP(domain)\n\n\n\n\n\n","category":"function"},{"location":"#EarthSciData:-Earth-Science-Data-Loaders-and-Interpolators","page":"Home","title":"EarthSciData: Earth Science Data Loaders and Interpolators","text":"Documentation for EarthSciData.","category":"section"},{"location":"#Installation","page":"Home","title":"Installation","text":"using Pkg\nPkg.add(\"EarthSciMLData\")","category":"section"},{"location":"#Feature-Summary","page":"Home","title":"Feature Summary","text":"This package contains data loaders for use with the EarthSciML ecosystem.","category":"section"},{"location":"#Feature-List","page":"Home","title":"Feature List","text":"Loader for GEOS-FP data.\nLoader for 2016 NEI emissions data.\nData outputters:\nNetCDFOutputter","category":"section"},{"location":"#Contributing","page":"Home","title":"Contributing","text":"Please refer to the SciML ColPrac: Contributor's Guide on Collaborative Practices for Community Packages for guidance on PRs, issues, and other matters relating to contributing.","category":"section"},{"location":"#Reproducibility","page":"Home","title":"Reproducibility","text":"<details><summary>The documentation of this EarthSciML package was built using these direct dependencies,</summary>\n\nusing Pkg # hide\nPkg.status() # hide\n\n</details>\n\n<details><summary>and using this machine and Julia version.</summary>\n\nusing InteractiveUtils # hide\nversioninfo() # hide\n\n</details>\n\n<details><summary>A more complete overview of all dependencies and their versions is also provided.</summary>\n\nusing Pkg # hide\nPkg.status(; mode = PKGMODE_MANIFEST) # hide\n\n</details>\n\nYou can also download the \n<a href=\"\n\nusing TOML\nusing Markdown\nversion = TOML.parse(read(\"../../Project.toml\", String))[\"version\"]\nname = TOML.parse(read(\"../../Project.toml\", String))[\"name\"]\nlink = Markdown.MD(\"https://github.com/EarthSciML/\"*name*\".jl/tree/gh-pages/v\"*version*\"/assets/Manifest.toml\")\n\n\">manifest</a> file and the\n<a href=\"\n\nusing TOML\nusing Markdown\nversion = TOML.parse(read(\"../../Project.toml\", String))[\"version\"]\nname = TOML.parse(read(\"../../Project.toml\", String))[\"name\"]\nlink = Markdown.MD(\"https://github.com/EarthSciML/\"*name*\".jl/tree/gh-pages/v\"*version*\"/assets/Project.toml\")\n\n\">project</a> file.","category":"section"},{"location":"geosfp/#Using-data-from-GEOS-FP","page":"GEOS-FP","title":"Using data from GEOS-FP","text":"This example demonstrates how to use the GEOS-FP data loader in the EarthSciML ecosystem. The GEOS-FP data loader is used to load data from the GEOS-FP dataset.\n\nFirst, let's initialize some packages and set up the GEOS-FP equation system.\n\nusing EarthSciData, EarthSciMLBase\nusing ModelingToolkit, DifferentialEquations\nusing ModelingToolkit: t, D\nusing Dates, Plots, DataFrames\nusing DynamicQuantities\nusing DynamicQuantities: dimension\n\n# Set up system\ndomain = DomainInfo(DateTime(2022, 1, 1), DateTime(2022, 1, 3);\n    latrange = deg2rad(-85.0f0):deg2rad(2):deg2rad(85.0f0),\n    lonrange = deg2rad(-180.0f0):deg2rad(2.5):deg2rad(175.0f0),\n    levrange = 1:11,\n    u_proto = zeros(Float32, 1, 1, 1, 1)\n)\n\ngeosfp = GEOSFP(\"4x5\", domain)\n\nNote that the GEOSFP function returns to things, an equation system and an object that can used to update the time in the underlying data loaders. We can see above the different variables that are available in the GEOS-FP dataset. But also, here they are in table form:\n\nvars = unknowns(geosfp)\nDataFrame(\n    :Name => [string(Symbolics.tosymbol(v, escape = false)) for v in vars],\n    :Units => [dimension(ModelingToolkit.get_unit(v)) for v in vars],\n    :Description => [ModelingToolkit.getdescription(v) for v in vars]\n)\n\nThe GEOS-FP equation system isn't an ordinary differential equation (ODE) system, so we can't run it by itself. To fix this, we create another equation system that is an ODE. (We don't actually end up using this system for anything, it's just necessary to get the system to compile.)\n\nstruct ExampleCoupler\n    sys::Any\nend\nfunction Example()\n    @parameters lat=0.0 [unit=u\"rad\"]\n    @parameters lon=0.0 [unit=u\"rad\"]\n    @variables c(t) = 5.0 [unit=u\"s\"]\n    System(\n        [D(c) ~ sin(lat * 6) + sin(lon * 6)],\n        t,\n        name = :ExampleSys,\n        metadata = Dict(CoupleType => ExampleCoupler)\n    )\nend\nfunction EarthSciMLBase.couple2(e::ExampleCoupler, g::EarthSciData.GEOSFPCoupler)\n    e, g = e.sys, g.sys\n    e = param_to_var(e, :lat, :lon)\n    ConnectorSystem([e.lat ~ g.lat, e.lon ~ g.lon], e, g)\nend\nexamplesys = Example()\n\nNow, let's couple these two systems together, and also add in advection and some information about the domain:\n\ncomposed_sys = couple(examplesys, domain, geosfp)\npde_sys = convert(PDESystem, composed_sys)\n\nNow, finally, we can run the simulation and plot the GEOS-FP wind fields in the result:\n\n(The code below is commented out because it is very slow right now. A faster solution is coming soon!)\n\n# discretization = MOLFiniteDifference([lat => 10, lon => 10, lev => 10], t, approx_order=2)\n# @time pdeprob = discretize(pde_sys, discretization)\n\n# pdesol = solve(pdeprob, Tsit5(), saveat=3600.0)\n\n# discrete_lon = pdesol[lon]\n# discrete_lat = pdesol[lat]\n# discrete_lev = pdesol[lev]\n# discrete_t = pdesol[t]\n\n# @variables meanwind₊u(..) meanwind₊v(..) examplesys₊c(..)\n# sol_u = pdesol[meanwind₊u(t, lat, lon, lev)]\n# sol_v = pdesol[meanwind₊v(t, lat, lon, lev)]\n# sol_c = pdesol[examplesys₊c(t, lat, lon, lev)]\n\n# anim = @animate for k in 1:length(discrete_t)\n#     p1 = heatmap(discrete_lon, discrete_lat, sol_c[k, 1:end, 1:end, 2], clim=(minimum(sol_c[:, :, :, 2]), maximum(sol_c[:, :, :, 2])),\n#             xlabel=\"Longitude\", ylabel=\"Latitude\", title=\"examplesys.c: $(Dates.unix2datetime(discrete_t[k]))\")\n#     p2 = heatmap(discrete_lon, discrete_lat, sol_u[k, 1:end, 1:end, 2], clim=(minimum(sol_u[:, :, :, 2]), maximum(sol_u[:, :, :, 2])), \n#             title=\"U\")\n#     p3 = heatmap(discrete_lon, discrete_lat, sol_v[k, 1:end, 1:end, 2], clim=(minimum(sol_v[:, :, :, 2]), maximum(sol_v[:, :, :, 2])),\n#             title=\"V\")\n#     plot(p1, p2, p3, size=(800, 500))\n# end\n# gif(anim, \"animation.gif\", fps = 8)","category":"section"}]
}
